do $$ begin create type moderation_decision_t as enum ('no_action', 'restrict', 'demote', 'remove', 'suspend_account'); exception when duplicate_object then null; end $$;
do $$ begin create type reviewer_type_t as enum ('human', 'ai_assisted', 'automated'); exception when duplicate_object then null; end $$;
alter table moderation_logs add column if not exists target_type text, add column if not exists decision moderation_decision_t, add column if not exists reasoning text, add column if not exists dsa_reason_code text, add column if not exists legal_basis text, add column if not exists reviewer_type reviewer_type_t, add column if not exists reviewer_id uuid references profiles(id), add column if not exists ai_model text, add column if not exists ai_confidence numeric(4,3), add column if not exists sor_submitted_at timestamptz, add column if not exists sor_submission_id text, add column if not exists visible_to_user boolean not null default true, add column if not exists decided_at timestamptz not null default now();
